	output		          		WIFI_UART0_TX,
	input 		          		WIFI_UART1_RX
);

//=======================================================
//  REG/WIRE declarations
//=======================================================
assign  BT_UART_TX = txd;
assign  rxd  = BT_UART_RX;

wire 				rts; 
wire 				cts; 
wire 				rxd;
wire 				txd;
wire	 [7:0]   uart_data;
wire	         rdempty;
wire	         write;
reg	     	   read;
reg	         cnt;

wire [7:0] w_scan_code;
wire       w_keyboard_ready;

wire [1:0] w_sensor_sel;
wire [15:0] w_limiar_temp;
wire [15:0] w_limiar_umid;

// ======================================================
// 	THINGS OF THE PROJECT
// ======================================================
reg [2:0] 	state = 3'd0;
reg [2:0] 	prev_state = 3'd0;
reg [15:0] 	temp1_reg, temp2_reg;

reg [15:0] s1_min;
reg [15:0] s1_max;
reg [15:0] s2_min;
reg [15:0] s2_max;
reg        	alerta_reg;
reg		  	buzzer_reg;

// Parâmetros da FSM
localparam IDLE   = 3'd0,
           GET_T1_L = 3'd1,
           GET_T1_H = 3'd2,
           GET_T2_L = 3'd3,
           GET_T2_H = 3'd4,
           GET_BIN  = 3'd5;
			  
reg [29:0] watchdog_msg_cnt; 
reg conexao_viva;
reg state_timeout;
wire vga_pixel_clk, buzzer_wire;

//=======================================================
//  Structural coding
//=======================================================

// UART Controller
uart_control UART0(
	.clk(CLOCK_50),
	.reset_n(KEY[0]),
	.write(write),
	.writedata(uart_data),
	.read(read),
	.readdata(uart_data),
	.rdempty(rdempty),
	.uart_clk_25m(cnt),
	.uart_tx(txd),
	.uart_rx(rxd)
);	

//=======================================================
// 		MODULO PRINCIPAL (FSM CORRIGIDA)
//=======================================================
always @(posedge CLOCK_50 or negedge KEY[0]) begin
    if (!KEY[0]) begin
        state       <= IDLE;
        read        <= 0;
        temp1_reg   <= 0;
        temp2_reg   <= 0;
        alerta_reg  <= 0;
        buzzer_reg  <= 0;
        // Inicialização crítica para lógica de min/max estável
        s1_max      <= 16'd0;
        s1_min      <= 16'hFFFF; 
        s2_max      <= 16'd0;
        s2_min      <= 16'hFFFF;
    end else begin
        read <= 0;
		  
        if (!rdempty && !read) begin
            read <= 1; 
            
            case (state)
                IDLE: begin
                    if (uart_data == 8'hAA) // Header
                        state <= GET_T1_L;
                end
                
                GET_T1_L: begin
                    temp1_reg[7:0] <= uart_data;
                    state <= GET_T1_H;
                end
                
                GET_T1_H: begin
                    temp1_reg[15:8] <= uart_data;
                    state <= GET_T2_L;
                end
                
                GET_T2_L: begin
                    temp2_reg[7:0] <= uart_data;
                    state <= GET_T2_H;
                end
                
                GET_T2_H: begin
                    temp2_reg[15:8] <= uart_data;
                    state <= GET_BIN;
                end
                
                GET_BIN: begin
                    alerta_reg <= (uart_data == 8'd1);
                    state <= IDLE;
                    
                   // if (temp1_reg > w_limiar_temp) begin
                   //     buzzer_reg <= 1'b1; 
                   // end else begin
                   //     buzzer_reg <= 1'b0; 
                   // end

                    // Lógica robusta de Máximos e Mínimos Históricos
                    if (temp1_reg > s1_max) s1_max <= temp1_reg;
                    if (temp1_reg < s1_min) s1_min <= temp1_reg;
                    
                    if (temp2_reg > s2_max) s2_max <= temp2_reg;
                    if (temp2_reg < s2_min) s2_min <= temp2_reg;
                end
                
                default: state <= IDLE;
            endcase
        end
    end
end
assign buzzer_wire = ((temp1_reg > w_limiar_temp) || (temp2_reg > w_limiar_umid));
//=======================================================
// WATCHDOG
//=======================================================
always @(posedge CLOCK_50 or negedge KEY[0]) begin
    if (!KEY[0]) begin
        watchdog_msg_cnt <= 0;
        conexao_viva <= 0;
        state_timeout <= 0;
        prev_state <= IDLE;
    end else begin
        if (state == prev_state) begin
            watchdog_msg_cnt <= watchdog_msg_cnt + 1;
            if (watchdog_msg_cnt > 30'd2_000_000_000) begin
                state_timeout <= 1; 
            end
        end else begin
				prev_state <= state;
            watchdog_msg_cnt <= 0;
            state_timeout <= 0;
        end
    end
end

assign LEDG[8] = alerta_reg; 
assign MPU_AD0_SDO = buzzer_wire; 
assign LEDR[8] = state_timeout;

assign HEX6 = 7'hFF;
assign HEX7 = 7'hFF;
assign HEX5 = 7'hFF;
assign HEX4 = 7'hFF;
assign HEX3 = 7'hFF;

always@(posedge CLOCK_50)
	cnt <= cnt + 1;

//=======================================================
// INSTANCIAÇÃO DO VGA COMPATIBILIZADA
//=======================================================
vga_with_hw_test_image instancia_vga (
    .clk(CLOCK_50),           
    .t1_temp(temp1_reg),    
    .t2_temp(temp2_reg),    
    .sensor_selecionado(w_sensor_sel),
    .pixel_clk(VGA_CLK),      
    .h_sync(VGA_HS),          
    .v_sync(VGA_VS),          
    .n_blank(VGA_BLANK_N),    
    .n_sync(VGA_SYNC_N),      
    .blue(VGA_B),             
    .green(VGA_G),            
    .red(VGA_R),               
	 .alerta(alerta_reg),
	 .alerta_critico(buzzer_wire), 
	 .s1_max(s1_max),          // Agora mapeado dinamicamente para os registradores
	 .s1_min(s1_min),          
	 .s2_max(s2_max),          
	 .s2_min(s2_min)          
);

//=======================================================
// INTEGRACAO DO TECLADO PS/2 E CONTROLE DE LIMIARES
//=======================================================
ps2 u_teclado (
    .iCLK_50    (CLOCK_50),
    .iRST_n     (KEY[1]), 
    .PS2_CLK    (PS2_CLK),
    .PS2_DAT    (PS2_DAT),
    .oSCAN_CODE (w_scan_code),
    .oREADY     (w_keyboard_ready)
);

keyboard_controle u_controle (
    .iCLK_50      (CLOCK_50),
    .iRST_n       (KEY[1]),
    .iSCAN_CODE   (w_scan_code),
    .iKEY_READY   (w_keyboard_ready),
    .oSENSOR_SEL  (w_sensor_sel),
    .oLIMIAR_TEMP (w_limiar_temp),
    .oLIMIAR_UMID (w_limiar_umid)
);

reg [15:0] w_limiar_exibicao;
always @(*) begin
    if (w_sensor_sel == 2'b00)
        w_limiar_exibicao = w_limiar_temp/100;
    else
        w_limiar_exibicao = w_limiar_umid;
end
display_7seg u_display_(
    .data(w_limiar_exibicao), // 14 bits cobrem até 16383, suficiente para 4 dígitos (9999)
    .ligaOUT(1'b1),
    .unid_display(HEX0), .dez_display(HEX1), .cen_display(), .mil_display()
);
// SEG7_LUT u_display_hex0 (.oSEG(HEX0), .iDIG(w_limiar_exibicao[3:0]));
// SEG7_LUT u_display_hex1 (.oSEG(HEX1), .iDIG(w_limiar_exibicao[7:4]));
SEG7_LUT u_display_hex2 (.oSEG(HEX2), .iDIG({2'b00, w_sensor_sel})); 

endmodule